$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location -LiteralPath $project
$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent
  New-Item -ItemType Directory -Force -Path $directory | Out-Null

  if (Test-Path -LiteralPath $target) {
    $backup = $target + ".backup-pedidos-pro-v2-" + (Get-Date -Format "yyyyMMddHHmmss")
    Copy-Item -LiteralPath $target -Destination $backup -Force
    Write-Host "Backup criado: $backup" -ForegroundColor DarkYellow
  }

  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)

  Write-Host "Criado/atualizado: $relativePath" -ForegroundColor Green
}

Write-Base64File "supabase\migrations\20260628_pedidos_pro_v2.sql" @"

"@

Write-Base64File "app\api\orders\[id]\route.ts" @"

"@

Write-Base64File "app\api\orders\[id]\comments\route.ts" @"

"@

Write-Base64File "app\api\orders\[id]\timeline\route.ts" @"

"@

Write-Base64File "app\api\orders\[id]\create-task\route.ts" @"

"@

Write-Base64File "app\api\orders\[id]\create-proposal\route.ts" @"

"@

Write-Base64File "app\painel\pedidos\[id]\page.tsx" @"

"@

$scriptsDir = Join-Path $project "scripts"
New-Item -ItemType Directory -Force -Path $scriptsDir | Out-Null

$patcherFile = Join-Path $scriptsDir "pedidos-pro-v2-patcher.cjs"
$patcherBase64 = @"

"@

$bytes = [System.Convert]::FromBase64String($patcherBase64.Trim())
$content = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText($patcherFile, $content, $utf8NoBom)

node $patcherFile

if ($LASTEXITCODE -ne 0) {
  Write-Host "Falha ao corrigir link de detalhes." -ForegroundColor Red
  exit $LASTEXITCODE
}

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Pedidos Pro V2 instalado." -ForegroundColor Green
Write-Host "Rode o SQL no Supabase: supabase\migrations\20260628_pedidos_pro_v2.sql" -ForegroundColor Yellow
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
